sql:
SELECT resource_name
FROM api_resources
WHERE created_at BETWEEN '2022-01-01 00:00:00' AND '2023-01-31 23:59:59';

SELECT resource_id, AVG(usage_count) as average_usage_count
FROM api_usage
GROUP BY resource_id;

external_knowledge:
- "Sluggish ship" metaphorically refers to users with a high average response time in their API usage; 
- "200-millisecond benchmark" indicates the threshold above which a user's performance is considered slow;
- "API voyages" refers to the activities of users who interact with and utilize API resources.

sql:
SELECT DISTINCT s.user_id
FROM api_subscriptions s
WHERE s.user_id NOT IN (
    SELECT u.user_id
    FROM api_usage u
);

SELECT user_id, AVG(usage_count) AS typical_usage_rate
FROM api_usage
GROUP BY user_id;

SELECT AVG(response_time) AS average_response_time 
FROM api_usage 
WHERE resource_id = '01' AND usage_date BETWEEN '2023-01-01' AND '2023-06-30';

SELECT COUNT(subscription_id)
FROM api_subscriptions
WHERE status = 'active';

SELECT COUNT(*)
FROM api_comments
WHERE user_id = 1;

SELECT history_id, change_date, change_type, details 
FROM api_resource_history
WHERE resource_id IN (
    SELECT resource_id 
    FROM api_descriptions
) AND resource_id NOT IN (
    SELECT resource_id 
    FROM api_subscriptions
);

external_knowledge:
- 'Whispers' metaphorically refer to comments;
- 'Artisans' represent developers;
- 'GetData' is the name of a specific API resource;
- 'Treasure chest' metaphorically represents an API resource.

